var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"마, 너무 쉬운거 아이가?","JPN":"おい、弱すぎちゃう？","ENG":"Hey, don't ya think that was too easy?","TWN":"嘖，會不會太簡單？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"학생들 다 나가떨어질 거야……. 널 기준으로 삼았다간…….","JPN":"生徒たち、みんな諦める……マリのレベルに合わせたら……","ENG":"The students will all leave... if we used your standards...","TWN":"那是對你而言……學生才打不過……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"리네도 올 줄은 몰랐는데…… 너무 오랜만이다.","JPN":"マリちゃんも来るとは思わなかったけど……本当に久しぶりだわ。","ENG":"I didn't know Rinae was going to be here too... It's been so long.","TWN":"我沒想到璃奈也會來……真的好久不見。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 보라야. 니 다인이한테 내 왔다는 얘기도 안 해줬나?","JPN":"あはは、シホ。あんた、タエにウチが来るって話さんかったの？","ENG":"Ah hah hah. Hey, Bora. You didn't tell her that I was comin'?","TWN":"哈哈哈，寶拉，你沒跟妲茵說我會來喔？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"……서프라이즈.","JPN":"……サプライズ。","ENG":"...Surprise.","TWN":"……驚喜。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L12_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"정말… 미리 말 해줬으면 좋았을 텐데….","JPN":"もう……あらかじめ言ってくれればよかったのに……","ENG":"Come on... It would've been nice if you had told me in advance...","TWN":"真是的…應該早點跟我說吧…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"리네도 정말 오랜만이야. 잘 지냈지?","JPN":"マリちゃんも本当に久しぶり。元気だった？","ENG":"Long time no see, Rinae. How've you been?","TWN":"我也好久沒見到璃奈，你過得好嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>은퇴</color>한 이후론 거의 해외에서만 살았잖아.","JPN":"<color=#ffd34c>引退</color>してからはほとんど海外にいたんでしょう？","ENG":"You've been living overseas ever since you <color=#ffd34c>retired</color>.","TWN":"你<color=#ffd34c>退休</color>後不是都待在國外嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내 오랜만에 <color=#ffd34c>귀국</color>한 김에, 니들 얼굴도 볼 겸 해서 와봤다.","JPN":"久々に<color=#ffd34c>帰国</color>したついでに、あんたたちに会おうと思ってな。","ENG":"I decided to swing by and see you after <color=#ffd34c>coming back</color> in a long time.","TWN":"我好不容易<color=#ffd34c>回國</color>一次，就趁這個機會來看看你們囉。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"베타 테스트는 관계자 외 참여 불가능하긴 한데, 우리 보라가 어떤 사람이고?","JPN":"ベータテストは関係者以外参加不可能やけど、さすがシホや。","ENG":"The beta test is only available to people involved, but you know Bora.","TWN":"通常非相關人員是不可以參與測試的，但你也知道寶拉這個人。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"의상은 어때……? 기억나?","JPN":"衣装はどう……？　覚えてる？","ENG":"How do you like the costumes...? Do you remember them?","TWN":"衣服怎麼樣……？記得嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"물론 기억하지. 이 나이에 입기엔 살짝 민망하지만.","JPN":"もちろん覚えてるよ。この歳で着るにはちょっと恥ずかしいけど。","ENG":"Of course, I remember. But it is a little embarrassing to wear something like this at this age.","TWN":"當然記得，但這個年紀穿有點丟臉。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"리네야. 이거 네가 만든거 맞지?","JPN":"マリちゃん、これあなたが作ったんでしょう？","ENG":"Rinae, you made this, right?","TWN":"璃奈，這是你做的吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하하, 이번에는 니들 민망하지 않게 내도 같이 입어봤다.","JPN":"はは、今回はあんたらが恥ずかしくないようにウチも着てみた。","ENG":"Ha ha. I wore it too this time so that you two won't be embarrassed.","TWN":"哈哈，我怕你們覺得丟臉，所以這次我也一起穿了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"……훗.","JPN":"……ふっ。","ENG":"...Heh.","TWN":"……呵。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"그럼……. 이제 할까……? 셋이서.","JPN":"じゃあ……始める……？　3人で。","ENG":"Then... Shall we...? The three of us?","TWN":"那就……開始吧……？我們三個。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"베타 테스트…….","JPN":"ベータテスト……","ENG":"Beta test...","TWN":"測試……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"우와아아아앗?!","JPN":"うわああああっ！？","ENG":"Whoooooa?!","TWN":"哇喔喔喔？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오?! 타이밍 직이네! 이 함 봐라. 이쁘제?","JPN":"おおっ！？　ナイスタイミングや！　見てみ。可愛いやろ？","ENG":"Oh?! Nice timing! Take a look at this. Pretty, ain't it?","TWN":"哇喔？！水喔！你看這套衣服，很美吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BORA_GAMECIRCLE_BUNNY_NULL","text":{"KOREA":"……뿅뿅.","JPN":"……ぴょんぴょん。","ENG":"...Pew pew.","TWN":"……咻咻。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L38_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"오, 왜, 왜…… 갑자기 왜 토끼 옷을 입고 있는 거예요?!","JPN":"お、な、なんで……どうしていきなりウサギの服を着てるんですか！？","ENG":"Uh, w-why... are you suddenly wearing a bunny suit?!","TWN":"為，為，為什麼……你會突然穿上兔女郎的衣服？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아니 애초에 이게 지금 무슨 상황이죠?!","JPN":"い、いや、そもそもこれってどういう状況なんですか！？","ENG":"W-what is going on right now?!","TWN":" 欸，不對，現在到底是什麼情況？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BORA_GAMECIRCLE_BUNNY_NULL","text":{"KOREA":"별로야……? 옷.","JPN":"気に入らない……？　服。","ENG":"You don't like it...? These clothes?","TWN":"不好看嗎……？衣服。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아뇨……. 그런 뜻이 아니라…….","JPN":"い、いいえ……そういう意味じゃなくて……","ENG":"N-no... That's not what I meant...","TWN":"沒，沒有啦……我不是這個意思……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 지금 박스가 무슨 얼굴 하고 있는지 뻔히 다 보이네.","JPN":"あはは、今ダンボールがどんな顔しとるか丸見えやな。","ENG":"Ah hah hah. I can see your face right through that box, Boxie.","TWN":"哈哈哈，我完全能想像現在紙箱裡面的你是什麼表情欸。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"코미페 나가믄, 홍보 좀 해볼라고 함 입혀 봤다.","JPN":"コミフェに出たら宣伝させよう思て着せてみた。","ENG":"I put it on her so she can promote our game when we go to Comic Festival.","TWN":"我想說穿這身去漫展的話，可以有點宣傳效果。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>바니걸 입고 기타 치는 미소녀</color>. 이건 무직건 먹힌다!","JPN":"<color=#ffd34c>バニーガール姿でギターを引く美少女</color>。これは絶対ウケる！","ENG":"<color=#ffd34c>A pretty girl in a bunny girl suit, playing the guitar</color>. This'll get everyone's attention!","TWN":"<color=#ffd34c>穿著兔女郎裝彈吉他的美少女</color>。保證大受歡迎！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"만화에서나 있을법한 설정이네요.","JPN":"マンガとかにありそうな設定ですね。","ENG":"It looks like something out of a comic book.","TWN":"這設定也太像漫畫裡的情節了吧。 "},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"근데 저기……. 왜 보라 누나만 입고 있는 건가요?","JPN":"でも、あの……どうしてシホさんだけ着てるんですか？","ENG":"But um... Why is Bora the only one wearing it?","TWN":"可是……為什麼只有寶拉姊姊穿？ "},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호~ 임마 박스!","JPN":"へえ～ダンボール！","ENG":"Ooh, Boxie!","TWN":"喔呵～紙箱你這小子！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"왜, 왜요……?","JPN":"な、なんですか……？","ENG":"W-what...?","TWN":"幹，幹嘛……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보고 싶나?","JPN":"ほかも見たいか？","ENG":"You wanna see it?","TWN":"你想看嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L7_1","type":"dialog","speaker":"BORA_GAMECIRCLE_BUNNY_NULL","text":{"KOREA":"……원해?","JPN":"……ほしい？","ENG":"...Do ya?","TWN":"……想嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아아아아 아니에요! 전 아무 말도 안 했어요!","JPN":"ちちちち違います！　僕、何も言ってません！","ENG":"N-n-n-n-no! I didn't say anything!","TWN":"我才沒有！！！我什麼話都沒說！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_02"},{"id":"L10_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 혹시 다인 누나는 아직 안 오셨나요?","JPN":"あの、タエさんはまだ来てないんですか？","ENG":"Um, is Dain not here yet?","TWN":"那個，妲茵姊姊還沒來嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"마침 몬스터 디자인 관련해서 할 얘기가…….","JPN":"ちょうどモンスターのデザインについて話が……","ENG":"I need to talk to her about the monster designs...","TWN":"我要找她談有關怪物設計的事……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리네야. 한번 입어 봤는데, 이거 가슴 쪽 사이즈가 작은 것 같아.","JPN":"マリちゃん。着てみたけど、これ胸のサイズがちょっと小さいと思うよ。","ENG":"Rinae. I tried it on, but it's a little small around the chest.","TWN":"璃奈，我試穿了一下，胸口這邊好像有點緊。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"헉?! 설마……?","JPN":"はっ！？　まさか……？","ENG":"Whoa?! No way...!","TWN":"什麼？！難道……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 박스 군 왔니?","JPN":"うん？　ダンボール君、来たの？","ENG":"Hmm? Is that you, Boxie?","TWN":"嗯？紙箱小朋友你來啦？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아~ 어제 몬스터 디자인이라면 다 됐는데, 지금 보여줄게.","JPN":"あ～昨日のモンスターデザインなら完成したんだけど、今見せてあげるね。","ENG":"Oh! I finished the design for the monster yesterday. I'll show it to you right now.","TWN":"喔～昨天怪物設計的部分我都弄好囉，我拿給你看。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"잠깐만요! 왜 아무렇지도 않게 들어오려 하시는 거예요?!","JPN":"ちょっと待ってください！　どうして平然と入って来ようとするんですか！？","ENG":"Why are you trying to come in so casually?!","TWN":"先等一下啦！就這樣衝進來不好吧？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 오늘 박스 임마 완전 수난이네. 만들어 보길 잘했다.","JPN":"あはは、こいつ困っとるや。作ってみて正解やったわ。","ENG":"Ah hah hah! Guess today's Boxie's day, eh? I'm glad I made them.","TWN":"哈哈哈，紙箱這小子今天被嚇到魂飛魄散欸，做這套衣服超值得。 "},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"BORA_GAMECIRCLE_BUNNY_NULL","text":{"KOREA":"수라장…….","JPN":"修羅場……","ENG":"Snafu...","TWN":"傻眼……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"근데 사이즈 틀릴 리가 없을 긴데…….","JPN":"せやけど、サイズはちゃんと合わせたはず……","ENG":"But I'm sure I measured the right size...","TWN":"不過尺寸應該不可能會錯才對……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아…… 그런기가. 그새 또 커졌구마.","JPN":"あ……それか。また大きくなってんな。","ENG":"Oh... I get it. They got bigger.","TWN":"啊……我知道了，妳又變大啦。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BORA_GAMECIRCLE_BUNNY_NULL","text":{"KOREA":"애초에…… 어떻게 알고 있는 거야……? 우리들의 사이즈.","JPN":"そもそも……どうやって知った……？　私たちのサイズ。","ENG":"Our sizes… how do you even know it…?","TWN":"不過……妳是怎麼知道的……？我們的尺寸。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다음에 <color=#ffd34c>용사 파티 의상</color> 만들어볼 때 한번 참고 해야긋네.","JPN":"今度<color=#ffd34c>勇者パーティーの衣装</color>を作る時に参考にさせてもらうよ。","ENG":"I should take note of it before making the <color=#ffd34c>clothes of the hero party</color>.","TWN":"之後做<color=#ffd34c>勇者小隊造型</color>時要參考一下。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"엇, 그거 비밀이었는데…?!","JPN":"あっ、それ秘密だったのに……！？","ENG":"Huh? But that was a secret…?!","TWN":"欸，那是秘密欸…？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"우와아앗! 들어오시면 안 돼요!","JPN":"うわああっ！　入ってきちゃダメです！","ENG":"WHOAAA! You can't come in here!","TWN":"哇啊啊！妳不可以進來！ "},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_WOOD"},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 전 이상한 거 절대 안 입을 거예요!","JPN":"ぼ、僕は絶対に変な服着ませんからね！","ENG":"I-I'm never wearing anything weird!","TWN":"我，我是絕對不會穿奇怪的衣服的！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이상한 거 아이다! 나중에 박스는 간지나는 걸로 입혀 줄게.","JPN":"変な服ちゃうわ！　後でダンボールは超カッコええの着せてやる。","ENG":"It's not weird! I'll make yours super cool, Boxie.","TWN":"一點也不奇怪！以後再給你做一套帥氣的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이, 입혀준다고요?!","JPN":"き、着せる！？","ENG":"T-that should be weird!","TWN":"要，要做給我？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자자 이제 다시 일하자. ","JPN":"さあさあ、また仕事しよう。 ","ENG":"Now, now. Let's get back to work.","TWN":"來，上工吧！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BORA_GAMECIRCLE_BUNNY_NULL","text":{"KOREA":"오늘은 이러고 할까……? 편한데…… 은근히.","JPN":"今日はこの格好でやる……？　らくちん……なんとなく。","ENG":"Maybe I can work in these clothes...? It's comfortable… kind of.","TWN":"今天就這麼穿著吧……？還蠻舒服的……沒想到。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_BUNNY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"갈아입고 와주세요…… 제발요.\xA0","JPN":"着替えてきてください……お願いします。\xA0","ENG":"Please change... I beg you.\xA0","TWN":"拜託妳去換件衣服吧……求求妳。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};